const source = $input.first();
const binary = source.binary ?? $binary ?? {};
const upload = binary.receipt;
const warnings = [];

function parseCategories(rawValue) {
  if (!rawValue) return { invalid: false, categories: [] };

  let parsed = rawValue;
  if (typeof rawValue === 'string') {
    try {
      parsed = JSON.parse(rawValue);
    } catch {
      return { invalid: true, categories: [] };
    }
  }

  if (!Array.isArray(parsed)) {
    return { invalid: true, categories: [] };
  }

  const categories = parsed
    .map((entry, index) => {
      if (!entry || typeof entry !== 'object') return null;
      const id = entry.id ?? entry.category_id ?? `category-${index + 1}`;
      const name = typeof entry.name === 'string' ? entry.name.trim() : '';
      if (!name) return null;
      const aliases = Array.isArray(entry.aliases)
        ? entry.aliases.filter((alias) => typeof alias === 'string').map((alias) => alias.trim()).filter(Boolean)
        : [];
      return { id: String(id), name, aliases };
    })
    .filter(Boolean);

  return { invalid: false, categories };
}

if (!upload) {
  return [{
    json: {
      valid: false,
      ok: false,
      statusCode: 400,
      error: {
        error_code: 'INVALID_INPUT',
        message: 'A receipt image is required in the multipart field "receipt".'
      }
    }
  }];
}

const mimeType = upload.mimeType ?? '';
if (!mimeType.startsWith('image/')) {
  return [{
    json: {
      valid: false,
      ok: false,
      statusCode: 400,
      error: {
        error_code: 'INVALID_INPUT',
        message: 'Only image uploads are supported for receipt OCR.'
      }
    },
    binary
  }];
}

const parsedCategoryResult = parseCategories(source.json?.categories_json ?? $json?.categories_json ?? null);
if (parsedCategoryResult.invalid) {
  warnings.push('categories_json_invalid');
}

return [{
  json: {
    valid: true,
    warnings,
    categories: parsedCategoryResult.categories,
    categories_json: source.json?.categories_json ?? $json?.categories_json ?? null,
    binaryPropertyName: 'receipt'
  },
  binary
}];

const payload = $json ?? {};
const validation = $("Validate OCR Core Request").first().json ?? {};
const requiredConfidence = Number($env.OCR_REQUIRED_CONFIDENCE ?? '0.65');
const fallbackCurrency = String($env.OCR_DEFAULT_CURRENCY ?? 'VND').toUpperCase();
const warnings = Array.isArray(validation.warnings) ? [...validation.warnings] : [];

function normalizeDate(value) {
  if (!value) return null;
  if (/^\d{4}-\d{2}-\d{2}T/.test(value)) return value;
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) return `${value}T00:00:00Z`;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return null;
  return date.toISOString();
}

function normalizeMoney(value, fallback = null) {
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : fallback;
}

function normalizePaymentMethod(rawValue) {
  const value = String(rawValue ?? '').trim().toLowerCase();
  if (!value) return null;
  if (/(cash|tien mat|tiền mặt)/.test(value)) return 'cash';
  if (/(bank|transfer|wire|chuyen khoan|chuyển khoản)/.test(value)) return 'bank_transfer';
  if (/(credit|visa|mastercard|amex)/.test(value)) return 'credit_card';
  if (/(debit|atm)/.test(value)) return 'debit_card';
  if (/(momo|zalopay|e-wallet|ewallet|wallet|apple pay|google pay)/.test(value)) return 'e_wallet';
  return 'other';
}

function buildError(errorCode, message, details = undefined, statusCode = 400) {
  return [{
    json: {
      ok: false,
      valid: false,
      statusCode,
      error: {
        error_code: errorCode,
        message,
        ...(details ? { details } : {})
      }
    }
  }];
}

if (payload.error || payload.statusCode >= 400) {
  return buildError('OCR_FAILED', 'Veryfi OCR request failed before a usable extraction was returned.');
}

const totalAmount = normalizeMoney(payload.total ?? payload.grand_total ?? payload.total_amount, null);
const taxAmount = normalizeMoney(payload.tax ?? payload.tax_amount ?? payload.tax_total ?? payload.total_tax, null);
const currency = String(payload.currency_code ?? payload.currency ?? fallbackCurrency).toUpperCase();
const merchantName = String(payload.vendor?.name ?? payload.vendor_name ?? payload.vendor ?? '').trim() || null;
const transactionDatetime = normalizeDate(payload.date ?? payload.transaction_date ?? payload.created_date);
const paymentMethod = normalizePaymentMethod(payload.payment?.display_name ?? payload.payment?.type ?? payload.payment_method ?? '');
const confidenceDetails = payload.confidence_details ?? {};
const confidenceValues = [];
for (const key of ['total', 'vendor_name', 'date']) {
  const value = Number(confidenceDetails[key]);
  if (!Number.isNaN(value)) confidenceValues.push(value);
}
const lowestConfidence = confidenceValues.length ? Math.min(...confidenceValues) : null;
if (payload.blurry === true) warnings.push('blur_detected');
if (lowestConfidence !== null && lowestConfidence < requiredConfidence) warnings.push('low_confidence_extraction');
if (taxAmount === null) warnings.push('missing_tax_amount');
if (!paymentMethod) warnings.push('missing_payment_method');

const missingFields = [];
if (!Number.isFinite(totalAmount)) missingFields.push('total_amount');
if (!currency) missingFields.push('currency');
if (!merchantName) missingFields.push('merchant_name');
if (!transactionDatetime) missingFields.push('transaction_datetime');
if (missingFields.length > 0) {
  return buildError('INSUFFICIENT_DATA', 'OCR completed but required receipt fields could not be derived reliably.', { missing_fields: missingFields, warnings }, 400);
}

const categorySignals = [
  payload.category,
  payload.document_type,
  merchantName,
  Array.isArray(payload.line_items) ? payload.line_items.map((item) => item?.description ?? '').join(' ') : ''
].filter(Boolean).join(' ').toLowerCase();

return [{
  json: {
    ok: true,
    valid: true,
    statusCode: 200,
    data: {
      merchant_name: merchantName,
      transaction_datetime: transactionDatetime,
      total_amount: totalAmount,
      tax_amount: taxAmount,
      currency,
      payment_method: paymentMethod,
      ai_suggested_category: null,
      ai_suggested_category_id: null,
      warnings,
      needs_review: warnings.length > 0
    },
    category_signal_text: categorySignals
  }
}];

const result = $json ?? {};
const data = result.data ?? {};
const validation = $("Validate OCR Core Request").first().json ?? {};
const categories = Array.isArray(validation.categories) ? validation.categories : [];
const source = String(result.category_signal_text ?? '').toLowerCase();
const warnings = Array.isArray(data.warnings) ? [...data.warnings] : [];

function tokenize(value) {
  return String(value ?? '')
    .toLowerCase()
    .split(/[^\p{L}\p{N}]+/u)
    .map((token) => token.trim())
    .filter((token) => token.length >= 2);
}

let bestMatch = null;
let bestScore = 0;
for (const category of categories) {
  const tokens = new Set([...tokenize(category.name), ...(Array.isArray(category.aliases) ? category.aliases.flatMap(tokenize) : [])]);
  let score = 0;
  for (const token of tokens) {
    if (token && source.includes(token)) score += token.length;
  }
  if (score > bestScore) {
    bestScore = score;
    bestMatch = category;
  }
}

if (!bestMatch) {
  warnings.push('category_match_unavailable');
} else {
  data.ai_suggested_category = bestMatch.name;
  data.ai_suggested_category_id = bestMatch.id;
}

data.warnings = [...new Set(warnings)];
data.needs_review = Boolean(data.needs_review || data.warnings.length > 0);

return [{
  json: {
    ok: true,
    statusCode: result.statusCode ?? 200,
    data
  }
}];

const result = $json ?? {};
const data = result.data ?? {};
return [{
  json: {
    ok: true,
    statusCode: result.statusCode ?? 200,
    data: {
      merchant_name: data.merchant_name ?? null,
      transaction_datetime: data.transaction_datetime ?? null,
      total_amount: Number.isFinite(data.total_amount) ? data.total_amount : 0,
      tax_amount: data.tax_amount ?? null,
      currency: data.currency ?? 'VND',
      payment_method: data.payment_method ?? null,
      ai_suggested_category: data.ai_suggested_category ?? null,
      ai_suggested_category_id: data.ai_suggested_category_id ?? null,
      warnings: Array.isArray(data.warnings) ? [...new Set(data.warnings)] : [],
      needs_review: Boolean(data.needs_review)
    }
  }
}];

const result = $json ?? {};
return [{
  json: {
    ok: false,
    statusCode: result.statusCode ?? 400,
    error: result.error ?? {
      error_code: 'OCR_FAILED',
      message: 'Receipt OCR Core did not return a structured error payload.'
    }
  }
}];
